module.exports=[50640,(a,b,c)=>{"use strict";Object.defineProperty(c,"__esModule",{value:!0}),Object.defineProperty(c,"InvariantError",{enumerable:!0,get:function(){return d}});class d extends Error{constructor(a,b){super(`Invariant: ${a.endsWith(".")?a:a+"."} This is a bug in Next.js.`,b),this.name="InvariantError"}}},93695,(a,b,c)=>{b.exports=a.x("next/dist/shared/lib/no-fallback-error.external.js",()=>require("next/dist/shared/lib/no-fallback-error.external.js"))},47450,a=>{"use strict";let b=[{slug:"fame-iii-subsidy-scheme-could-reshape-the-ev-market",category:"Policy · Analysis",title:"India's FAME III subsidy scheme could reshape the EV market — here's what we know",excerpt:"The government is expected to announce a revised subsidy structure that extends support to private four-wheelers for the first time, potentially unlocking demand from a segment that has remained price-sensitive.",author:"Priya Mehta",readTime:"6 min read",published:"2 hours ago",body:["India's expected FAME III framework is shaping up to be more ambitious than earlier EV incentive rounds. Officials are reportedly focusing on a broader adoption curve instead of limiting support to narrow use-cases.","The biggest shift could be support for private four-wheelers, a category that has struggled to break into the mainstream because of upfront cost. If that arrives, it would materially improve affordability for urban families considering their first EV.","Automakers, charging providers, and battery suppliers would all feel the impact. Companies with local manufacturing and strong entry-level products are likely to benefit first, while premium players may gain later through demand spillover.","The open question is execution. Incentives alone will not solve charging access, financing friction, or resale uncertainty, but a credible long-term policy could still change the pace of India's EV transition."]},{slug:"march-2025-ev-report-india-crosses-200000-monthly-units",category:"Market · India",title:"March 2025 EV report: India crosses 200,000 monthly units for the first time — a milestone five years in the making",excerpt:"Passenger EVs, two-wheelers, and commercial vehicles all posted record numbers this March. We examine what drove the surge and whether it's sustainable.",author:"Data Desk",readTime:"9 min read",published:"1 day ago",body:["India's EV market crossed 200,000 monthly units for the first time, marking a symbolic threshold for the industry. The jump was supported by seasonal buying, better product availability, and improving financing options.","Two-wheelers remained the largest contributor by volume, but passenger vehicles showed sharper momentum than many analysts expected. That suggests buyer confidence is broadening beyond early adopters.","Commercial and fleet operators also played a role, especially in urban logistics. Their economics continue to improve as fuel savings become easier to model and charger uptime gets better.","The next few months will reveal whether this is a one-off spike or the beginning of a more durable adoption trend."]},{slug:"solid-state-batteries-coming-to-india-sooner-than-expected",category:"Battery · Research",title:"Solid-state batteries are coming to India sooner than expected — Tata's R&D chief speaks",excerpt:"An exclusive conversation on the 2027 timeline, cell chemistry choices, and why India's heat conditions require a unique approach.",author:"Rajan Verma",readTime:"7 min read",published:"2 days ago",body:["Solid-state battery development is accelerating, and Indian road conditions are shaping the engineering priorities in a different way than colder markets. Heat resilience and charging stability remain central concerns.","Executives say commercial readiness still depends on manufacturing yield and pack integration, but confidence around mid-decade pilots is growing. That timeline now feels more real than speculative.","For Indian OEMs, the prize is not only more range. Better thermal behavior and improved energy density could unlock packaging flexibility and safer fast charging in dense urban conditions.","Even so, mass-market deployment will likely remain gradual, with premium segments and limited fleet programs leading first."]},{slug:"how-charge-zone-plans-to-deploy-10000-dcfc-stations-by-2026",category:"Charging · Infra",title:"How Charge Zone plans to deploy 10,000 DCFC stations by 2026",excerpt:"The startup's blueprint: highways first, then Tier 2 cities, then apartments. We map out the strategy and the funding behind it.",author:"Ananya Singh",readTime:"5 min read",published:"3 days ago",body:["Charge Zone is betting that highway reliability will define brand trust before urban density does. Its rollout strategy prioritizes corridors where charger confidence still decides whether long-distance EV travel feels practical.","The company plans to deepen coverage in Tier 2 cities once those backbone routes are stable. That sequence is intended to improve utilization instead of scattering assets too early.","Apartment charging remains the hardest layer because of housing society approvals and electrical upgrades. That is where partnerships, not hardware, may become the real differentiator.","If execution holds, the network could become one of the most important demand enablers for India's next EV growth phase."]},{slug:"lfp-vs-nmc-why-indian-oems-are-betting-on-iron-phosphate",category:"Battery Tech · India",title:"LFP vs NMC: Why Indian OEMs are betting on iron-phosphate chemistry despite the range trade-off",excerpt:"Tata, MG, and BYD have all standardised on LFP for their Indian lineup. We break down the thermal, cost, and longevity reasons behind this shift.",author:"Rajan Verma",readTime:"8 min read",published:"Yesterday",body:["LFP chemistry is increasingly winning in India because it aligns well with price sensitivity and thermal safety expectations. For many buyers, predictable ownership cost matters more than absolute headline range.","Manufacturers also value LFP's durability in demanding climates. That matters in a market where battery confidence still influences resale value and first-time buyer trust.","NMC remains relevant for performance-focused vehicles, but its cost profile can be harder to justify at scale. As local production matures, LFP's value proposition may become even stronger.","The trade-off is clear: slightly less energy density in exchange for a chemistry that feels better suited to India's mass market."]},{slug:"indias-dc-fast-charger-rollout-is-stalling",category:"Charging Infra · Analysis",title:"India's DC fast charger rollout is stalling — and the culprit is land, not money",excerpt:"Despite aggressive targets, DCFC deployment is running at 40% of planned pace. We investigated 6 months of tender data across 12 states.",author:"Ananya Singh",readTime:"11 min read",published:"2 days ago",body:["Fast charger deployment is increasingly bottlenecked by site access rather than capital availability. Land approvals, utility coordination, and right-of-way negotiations are delaying projects across multiple states.","That distinction matters because it changes the policy response. Subsidies and financing support help, but they cannot solve local execution friction on their own.","Operators say the most attractive sites are often the hardest to secure. As a result, rollout targets may look healthy on paper while high-demand corridors remain underserved.","Unless permitting and land-use processes improve, charger deployment could continue missing the pace required for the next wave of passenger EV growth."]},{slug:"ather-rizta-review-family-scooter-electric-practical",category:"Two-Wheelers · Review",title:"Ather Rizta review: The family scooter that finally makes electric practical for Tier 2 cities",excerpt:"After 1,200km across Jaipur, Kota, and Ajmer — a real-world verdict on range anxiety, service access, and running costs.",author:"Kavya Nair",readTime:"14 min read",published:"3 days ago",body:["The Rizta feels designed around everyday family usage instead of enthusiast expectations. That makes it a more meaningful product for India's next EV buyer segment.","Range confidence was solid across mixed riding conditions, and the ergonomics suit shared household use better than sportier electric scooters.","Service access still matters outside metros, but the overall ownership story is stronger than many earlier-generation products. Running costs remain one of the vehicle's clearest advantages.","For Tier 2 cities, practicality often wins over novelty, and that is exactly where this scooter performs best."]},{slug:"march-2025-ev-sales-data-tata-dominates-mahindra-surges-ola-slips",category:"Market · Data",title:"March 2025 EV sales data: Tata dominates, Mahindra surges, Ola slips",excerpt:"Full breakdown of monthly registration data across categories — with segment-wise growth rates and market share shifts since Q4 2024.",author:"Data Desk",readTime:"5 min read",published:"4 days ago",body:["March sales data showed Tata maintaining category leadership while Mahindra posted one of the strongest growth curves in the market. Ola, meanwhile, lost some momentum relative to recent quarters.","The shape of the market is changing as newer launches widen consumer choice. That makes share gains increasingly dependent on execution, not just being early.","Brand performance varied sharply by segment, reminding investors that the EV market is no longer a single-story category. Two-wheelers, passenger cars, and fleet demand are evolving at different speeds.","As product pipelines expand, monthly data will become even more important for spotting who is gaining sustainable traction."]},{slug:"pli-2-revised-targets-mean-for-battery-startups",category:"Policy · Startup",title:"PLI 2.0 for Advanced Chemistry Cells: What the revised targets mean for battery startups",excerpt:"The government's revised PLI scheme raises the performance bar for cell manufacturers. We speak to three startups navigating the new landscape.",author:"Kiran Bhat",readTime:"10 min read",published:"5 days ago",body:["The revised PLI framework is raising expectations around performance, localization, and scale. For battery startups, that creates both pressure and opportunity.","Early-stage manufacturers now need sharper execution on milestones that were previously more flexible. That may favor teams with stronger supply-chain discipline and industrial partnerships.","At the same time, clearer targets can help serious players stand out in a crowded policy-driven environment. Investors often prefer a rulebook they can model, even if it is stricter.","The real test will be whether startups can move from pilot credibility to reliable manufacturing throughput under the new regime."]},{slug:"mahindra-be07-first-drive-most-range-tested-in-india",category:"Passenger EVs · Launch",title:"Mahindra BE.07 first drive: Bold, brash, and the most range we've tested in India",excerpt:"At 683km ARAI, the BE.07 rewrites the range narrative. But it's the driving dynamics and software that truly set it apart from the Nexon EV.",author:"Meera Pillai",readTime:"12 min read",published:"6 days ago",body:["Mahindra's BE.07 aims to reset expectations for domestic long-range EVs. Its combination of bold design, improved software, and strong claimed efficiency gives it immediate market presence.","The vehicle's headline range is what attracts attention first, but day-to-day usability and cabin experience are what make it feel competitive. Those details matter more as the segment matures.","Driving dynamics appear tuned for confidence rather than softness, which helps the car feel more premium on first impression. That choice may resonate with buyers moving up from compact SUVs.","If pricing stays disciplined, the BE.07 could become one of the most important launches in India's passenger EV market."]},{slug:"tata-curvv-ev-deliveries-begin-47000-bookings-pending",category:"Passenger · Trending",title:"Tata Curvv EV deliveries begin — 47,000 bookings pending",excerpt:"Deliveries are now underway for one of Tata's most anticipated EV launches, with a large booking backlog still in the queue.",author:"EVTimes Desk",readTime:"4 min read",published:"Today",body:["Tata has started deliveries of the Curvv EV, turning one of the year's biggest booking stories into a real volume test for the company. The pending order bank suggests demand remains strong even as competition rises.","What happens next will depend on how quickly Tata can convert bookings into customer handovers without compromising the ownership experience. Delivery pace often shapes early sentiment as much as the product itself.","For the broader market, the Curvv EV is another signal that Indian buyers are now responding to design-led electric products, not only value-led ones."]},{slug:"v2g-in-india-tata-power-pilots-bidirectional-charging-in-mumbai",category:"Charging · Trending",title:"V2G in India: Tata Power pilots bidirectional charging in Mumbai",excerpt:"The pilot explores how parked EVs can support local grid stability while opening up a new ownership value proposition.",author:"Ananya Singh",readTime:"6 min read",published:"Today",body:["Tata Power's Mumbai pilot is one of the clearest local tests yet for vehicle-to-grid technology in India. The concept could eventually let EV owners send stored energy back to the grid during peak demand windows.","The commercial case will depend on tariff design, hardware compatibility, and policy support. Without those layers, V2G remains more promising than practical.","Still, the pilot matters because it moves the conversation from theory to real-world operating conditions in an Indian city context."]},{slug:"what-the-new-bis-standards-mean-for-ev-charger-safety",category:"Policy · Trending",title:"Explained: What the new BIS standards mean for EV charger safety",excerpt:"India's updated charger standards could influence hardware design, installation norms, and long-term consumer trust.",author:"Policy Desk",readTime:"7 min read",published:"Yesterday",body:["The latest BIS standards are meant to improve charger safety, consistency, and deployment quality across public and private installations. That may sound technical, but the impact reaches end users directly.","Clearer standards can reduce interoperability confusion and improve installer accountability. They also create a firmer baseline for operators scaling networks quickly.","In the long run, safety standards are not just compliance paperwork. They are part of how the market builds trust with mainstream EV buyers."]},{slug:"reliance-2b-battery-gigafactory-progress-report",category:"Battery · Trending",title:"Reliance's $2B battery gigafactory — progress report",excerpt:"A status check on one of India's most closely watched battery manufacturing bets.",author:"Market Desk",readTime:"5 min read",published:"Yesterday",body:["Reliance's battery gigafactory remains one of the most important long-term industrial stories in India's EV supply chain. The project's pace and execution will influence how much local battery value creation the country can capture.","Investors are watching timelines, partnerships, and cell technology choices closely. Each of those factors affects both economics and strategic positioning.","While the buildout is still developing, progress on large-scale battery manufacturing will shape the next phase of India's EV competitiveness."]},{slug:"why-chinas-ev-dominance-is-a-warning-for-indias-nascent-industry",category:"Global · Insight",title:"Why China's EV dominance is a warning for India's nascent industry",excerpt:"China's scale advantage offers lessons for policymakers and startups trying to build a durable Indian EV ecosystem.",author:"Priya Mehta",readTime:"16 min read",published:"3 days ago",body:["China's EV lead did not emerge from a single subsidy or isolated company success. It came from patient industrial planning, manufacturing depth, and relentless ecosystem coordination.","For India, the warning is not simply that China is ahead. It is that catching up requires decisions that reach beyond headline announcements into supply chains, talent, infrastructure, and export strategy.","The more useful question is not whether India can copy China's path exactly, but which structural lessons it can adapt before market concentration hardens further."]},{slug:"the-bms-arms-race-how-indian-startups-are-building-better-battery-management",category:"Technology · Deep Dive",title:"The BMS arms race: How Indian startups are building better battery management",excerpt:"Battery management is becoming a competitive frontier as startups push for safer, smarter, and more adaptive systems.",author:"Rajan Verma",readTime:"13 min read",published:"4 days ago",body:["Battery management systems are quietly becoming one of the most strategic layers in EV product design. Better software can improve safety, charging behavior, battery life, and user confidence all at once.","Indian startups are treating BMS as a serious product category rather than a hidden subsystem. That shift is helping them compete on intelligence and adaptability, not just hardware cost.","As batteries become more central to vehicle economics, the teams that build better control systems may end up owning a disproportionate share of value."]},{slug:"fame-iii-too-little-too-late-india-needs-10-year-ev-policy",category:"Opinion · Policy",title:"FAME III is too little, too late — India needs a 10-year EV industrial policy, not another subsidy patch",excerpt:"Short-cycle incentives cannot replace a durable industrial roadmap for India's EV transition.",author:"Priya Mehta",readTime:"8 min read",published:"2 days ago",body:["Short-term subsidy design may help demand at the margin, but it does not provide the long-duration certainty manufacturers and suppliers need. Industrial planning works best when capital can model a stable policy horizon.","India's EV transition now needs deeper coordination across supply chains, charging rollout, raw materials strategy, and export competitiveness. Those pieces do not move fast enough under patchwork incentives alone.","A ten-year framework would not solve everything overnight, but it would change the quality of decisions being made today by automakers, battery companies, and infrastructure investors."]},{slug:"real-bottleneck-isnt-batteries-its-software-engineers",category:"Opinion · Technology",title:"The real bottleneck isn't batteries — it's software engineers who understand both EVs and India's grid",excerpt:"The next stage of EV competition may be decided as much by systems software as by hardware.",author:"Rajan Verma",readTime:"7 min read",published:"3 days ago",body:["Battery chemistry gets most of the public attention, but the practical EV stack increasingly depends on software quality. Charging logic, energy management, thermal control, and diagnostics all shape real-world performance.","India has strong engineering talent, but the overlap between mobility systems and grid-aware software is still limited. That makes recruiting and training a strategic issue for ambitious EV companies.","The firms that build this talent advantage early may end up outperforming rivals even when hardware looks similar on paper."]},{slug:"indias-charging-network-needs-single-interoperability-standard",category:"Opinion · Infrastructure",title:"Why India's charging network needs a single interoperability standard — now, before it's too late",excerpt:"Fragmentation today could harden into long-term inefficiency if standards remain unsettled.",author:"Ananya Singh",readTime:"9 min read",published:"4 days ago",body:["Interoperability sounds like a back-office standards debate until consumers run into incompatible hardware, patchy payment systems, or unreliable charging sessions. At that point, fragmentation becomes a demand problem.","India still has a chance to consolidate around clearer operating norms before the public network grows too uneven. The longer that alignment is delayed, the harder it becomes to standardize without disruption.","A unified framework would improve user trust, simplify operator scaling, and make the charging ecosystem more investable."]}];a.s(["getArticleBySlug",0,function(a){return b.find(b=>b.slug===a)},"newsArticles",0,b])},26758,a=>{a.v("/_next/static/media/favicon.0x3dzn~oxb6tn.ico"+(globalThis.NEXT_CLIENT_ASSET_SUFFIX||""))},38872,a=>{"use strict";let b={src:a.i(26758).default,width:256,height:256};a.s(["default",0,b])},65598,a=>{"use strict";var b=a.i(7997),c=a.i(95936),d=a.i(47450);a.s(["default",0,function(){return(0,b.jsx)("main",{className:"article-page",children:(0,b.jsx)("div",{className:"article-shell",children:(0,b.jsxs)("section",{className:"article-detail",children:[(0,b.jsx)("div",{className:"article-kicker",children:"News Routes"}),(0,b.jsx)("h1",{children:"Open any news story by slug"}),(0,b.jsxs)("p",{className:"article-standfirst",children:["These links open as real routes like ",(0,b.jsx)("code",{children:"/news-title"})," so the browser URL changes when you click a story."]}),(0,b.jsx)("div",{className:"route-list",children:d.newsArticles.map(a=>(0,b.jsxs)(c.default,{href:`/${a.slug}`,className:"route-card",children:[(0,b.jsx)("span",{className:"route-category",children:a.category}),(0,b.jsx)("strong",{children:a.title}),(0,b.jsx)("span",{children:a.excerpt})]},a.slug))})]})})})}])},22243,a=>{a.n(a.i(65598))}];

